using System.ComponentModel.DataAnnotations;

namespace DocSummary.Models;

public class SummarizeRequest
{
    [Required]
    [MinLength(1)]
    public string Text { get; set; } = string.Empty;

    /// <summary>
    /// Maximum number of sentences in the summary. Defaults to 3.
    /// </summary>
    [Range(1, 20)]
    public int MaxSentences { get; set; } = 3;
}

namespace DocSummary.Models;

public class SummarizeResponse
{
    public string Summary { get; set; } = string.Empty;

    public int OriginalLength { get; set; }

    public int SummaryLength { get; set; }
}

namespace DocSummary.Services;

public interface IDocumentSummarizationService
{
    string Summarize(string text, int maxSentences);
}

using System.Text.RegularExpressions;

namespace DocSummary.Services;

/// <summary>
/// Extractive summarizer that scores sentences by term frequency
/// and returns the top-ranked ones in their original order.
/// </summary>
public partial class ExtractiveSummarizationService : IDocumentSummarizationService
{
    private static readonly HashSet<string> StopWords = new(StringComparer.OrdinalIgnoreCase)
    {
        "a","an","the","and","or","but","is","are","was","were","be","been","being",
        "have","has","had","do","does","did","will","would","shall","should","may",
        "might","must","can","could","i","you","he","she","it","we","they","me","him",
        "her","us","them","my","your","his","its","our","their","this","that","these",
        "those","in","on","at","to","for","of","with","by","from","as","into","about",
        "between","through","during","before","after","above","below","not","no","nor",
        "so","if","then","than","too","very","just","also","more","most","some","any",
        "each","every","all","both","few","many","much","own","other","another","such",
        "what","which","who","whom","when","where","why","how"
    };

    public string Summarize(string text, int maxSentences)
    {
        var sentences = SplitSentences(text);

        if (sentences.Count <= maxSentences)
            return string.Join(" ", sentences);

        var wordFrequencies = BuildWordFrequencies(sentences);
        var scoredSentences = sentences
            .Select((s, index) => (Sentence: s, Index: index, Score: ScoreSentence(s, wordFrequencies)))
            .OrderByDescending(x => x.Score)
            .Take(maxSentences)
            .OrderBy(x => x.Index) // preserve original order
            .Select(x => x.Sentence);

        return string.Join(" ", scoredSentences);
    }

    private static List<string> SplitSentences(string text)
    {
        return SentenceRegex()
            .Split(text)
            .Select(s => s.Trim())
            .Where(s => s.Length > 0)
            .ToList();
    }

    private static Dictionary<string, int> BuildWordFrequencies(List<string> sentences)
    {
        var freq = new Dictionary<string, int>(StringComparer.OrdinalIgnoreCase);

        foreach (var sentence in sentences)
        {
            foreach (var word in ExtractWords(sentence))
            {
                if (!StopWords.Contains(word) && word.Length > 1)
                    freq[word] = freq.GetValueOrDefault(word) + 1;
            }
        }

        return freq;
    }

    private static double ScoreSentence(string sentence, Dictionary<string, int> wordFrequencies)
    {
        var words = ExtractWords(sentence);
        if (words.Count == 0)
            return 0;

        double score = 0;
        foreach (var word in words)
        {
            if (wordFrequencies.TryGetValue(word, out var freq))
                score += freq;
        }

        return score / words.Count;
    }

    private static List<string> ExtractWords(string text)
    {
        return WordRegex()
            .Matches(text)
            .Select(m => m.Value)
            .ToList();
    }

    [GeneratedRegex(@"(?<=[.!?])\s+", RegexOptions.Compiled)]
    private static partial Regex SentenceRegex();

    [GeneratedRegex(@"\b[a-zA-Z]+\b", RegexOptions.Compiled)]
    private static partial Regex WordRegex();
}

using DocSummary.Models;
using DocSummary.Services;
using Microsoft.AspNetCore.Mvc;

namespace DocSummary.Controllers;

[ApiController]
[Route("api/[controller]")]
public class SummarizeController : ControllerBase
{
    private readonly IDocumentSummarizationService _summarizer;

    public SummarizeController(IDocumentSummarizationService summarizer)
    {
        _summarizer = summarizer;
    }

    [HttpPost]
    public ActionResult<SummarizeResponse> Summarize([FromBody] SummarizeRequest request)
    {
        var summary = _summarizer.Summarize(request.Text, request.MaxSentences);

        return Ok(new SummarizeResponse
        {
            Summary = summary,
            OriginalLength = request.Text.Length,
            SummaryLength = summary.Length
        });
    }
}

